<div class="d-flex justify-content-between align-items-center mb-4"><div><p class="text-uppercase fw-semibold archive-kicker-dark mb-1">Trust & safety</p><h1 class="h2 mb-0">Order Disputes</h1></div><a class="btn btn-outline-secondary" href="<?= e(url('/admin')) ?>">Dashboard</a></div>
<?php if($disputes===[]):?><div class="archive-card p-4 text-muted">No disputes.</div><?php else:?><div class="row g-3"><?php foreach($disputes as $dispute):?><div class="col-12"><div class="archive-card p-4"><div class="row g-3"><div class="col-lg-7"><div><strong>Dispute #<?= e((string)$dispute['id']) ?> · Order #<?= e((string)$dispute['order_id']) ?></strong> <span class="badge text-bg-<?= $dispute['status']==='resolved'?'success':'warning' ?>"><?= e($dispute['status']) ?></span></div><div class="small text-muted">Buyer <?= e($dispute['buyer_username']) ?> · Seller <?= e($dispute['seller_username']) ?> · Opened by <?= e($dispute['opener_username']) ?></div><div class="mt-2"><strong><?= e(ucwords(str_replace('_',' ',$dispute['reason']))) ?></strong></div><div><?= nl2br(e($dispute['details'])) ?></div><?php if(!empty($dispute['evidence_notes'])):?><div class="alert alert-light mt-2 mb-0"><strong>Evidence:</strong> <?= nl2br(e($dispute['evidence_notes'])) ?></div><?php endif;?><div class="mt-2"><a class="btn btn-sm btn-outline-dark" href="<?= e(url('/admin/orders/messages?id='.(int)$dispute['order_id'])) ?>">Review order messages</a></div><?php if($dispute['status']==='resolved'):?><div class="mt-3 small"><strong>Resolution:</strong> <?= e(ucwords(str_replace('_',' ',$dispute['resolution']))) ?><br>Refund total: PHP <?= e(number_format((float)$dispute['refund_total'],2)) ?> (credit <?= e(number_format((float)$dispute['refund_store_credit'],2)) ?>, external <?= e(number_format((float)$dispute['refund_external'],2)) ?>)<br><?= nl2br(e($dispute['resolution_notes'])) ?></div><?php endif;?></div><div class="col-lg-5"><?php if($dispute['status']!=='resolved'):?><form method="post" action="<?= e(url('/admin/disputes/resolve?id='.(int)$dispute['id'])) ?>"><label class="form-label">Resolution</label><select class="form-select mb-2" name="resolution" required><option value="denied">Deny dispute</option><option value="no_action">No financial action</option><option value="partial_refund">Partial refund</option><option value="full_refund">Full refund</option></select><label class="form-label">Partial refund total</label><input class="form-control mb-2" type="number" name="refund_total" min="0" step="0.01"><div class="form-text mb-2">Store credit is reversed automatically. External cash must be refunded outside MTGHub and recorded in the notes.</div><label class="form-label">Resolution notes</label><textarea class="form-control" name="resolution_notes" minlength="10" maxlength="3000" rows="4" required></textarea><button class="btn btn-archive mt-2">Resolve dispute</button></form><?php endif;?></div></div></div></div><?php endforeach;?></div><?php endif;?>
